characters.behaviorScript:
function update(incomingForce, attackType) {
    if (attackType === 'rigid') {
        redirectKineticForce(incomingForce);
        FlowMeter.increment(15);
    }
    if (health.tookDamage) {
        Shader.setFloat('_GauntletExtrusion', 2.5); // Reactive Hardening
    }
}

function executeInvasion() {
    target = "Onalym Nexus";
    unleashVoidShockwave();
    overwriteCoreLogic();
}

function aerialCombat() {
    if (player.isFlappingArms || thrusters.active) {
        maintainAltitude();
        if (FlowMeter.isFull) {
            executeVoidLightningStomp();
        }
    } else if (distanceTo(Lyra.SolarBarrier) > AuraRadius) {
        applyDefenseDebuff();
    }
}

function processDreamscape() {
    if (geometry.state === 'brittle' || geometry.state === 'gray') {
        snapMemoryFragments();
        if (ParityCheck.fails > threshold) {
            triggerEnvironmentCrash(previousSaveState);
        }
    }
    commandReverie('toggle_form');
}

function bossPhase() {
    spawnShadowClones();
    castSicklyGreenBlackVoidfire();
    if (hasStatus('Blinding_Truth') && hasStatus('Dream_Harmony')) {
        implodeVoid();
        restoreIngris();
    }
}
